from string_utils.manipulation import roman_encode

def test__roman_encode_invalid_values():
    """Test roman_encode's handling of invalid and edge cases."""

    invalid_inputs = [
        -1,          # negative value
        0,           # edge case zero
        4000,        # above upper bounds
        "some_string",  # wrong type
        None,        # None input
        [],          # empty list
        {}           # empty dictionary
    ]

    for input_value in invalid_inputs:
        try:
            roman_encode(input_value)
            assert False, f"Expected ValueError for input: {input_value}"
        except ValueError as e:
            assert True  # Expected behavior
        except Exception as e:
            assert False, f"Unexpected exception for input: {input_value} - {str(e)}"
